nta.declaration:
const int N = 4;
const int Z = 4;

const int LANES = 4;
const int INTENTS = 3;
const int MAX_ZONES = 3;
const int NO_CZ = 4;

const int NORTH = 0;
const int SOUTH = 1;
const int EAST  = 2;
const int WEST  = 3;

const int STRAIGHT   = 0;
const int TURN_RIGHT = 1;
const int TURN_LEFT  = 2;

/*
    Timing model:
    T_NORMAL = normal arrival time from detection point
    T_LATE   = latest allowed arrival time
    T_ZONE   = time spent per critical zone
*/
const int T_NORMAL = 6;
const int T_LATE   = 8;
const int T_ZONE   = 1;

/*
    Critical-zone route map.

    Zone numbers:
    0 = CZ1
    1 = CZ2
    2 = CZ3
    3 = CZ4
    4 = NO_CZ / unused
*/
const int route[LANES][INTENTS][MAX_ZONES] = {
    /* NORTH */
    {
        {2, 0, NO_CZ},   /* straight: CZ3 -> CZ1 */
        {2, NO_CZ, NO_CZ}, /* right: CZ3 */
        {2, 0, 1}        /* left: CZ3 -> CZ1 -> CZ2 */
    },

    /* SOUTH */
    {
        {1, 3, NO_CZ},   /* straight: CZ2 -> CZ4 */
        {1, NO_CZ, NO_CZ}, /* right: CZ2 */
        {1, 3, 2}        /* left: CZ2 -> CZ4 -> CZ3 */
    },

    /* EAST */
    {
        {3, 2, NO_CZ},   /* straight: CZ4 -> CZ3 */
        {3, 2, 0},       /* right: CZ4 -> CZ3 -> CZ1 */
        {3, NO_CZ, NO_CZ}  /* left: CZ4 */
    },

    /* WEST */
    {
        {0, 1, NO_CZ},   /* straight: CZ1 -> CZ2 */
        {0, 1, 3},       /* right: CZ1 -> CZ2 -> CZ4 */
        {0, NO_CZ, NO_CZ}  /* left: CZ1 */
    }
};

int[0,N] occ[Z];

bool badOcc = false;

const int HORIZON = 12;
const int SIM_END_TICK = 5;

int[0,HORIZON-1] now = 0;
int[0,SIM_END_TICK] simTick = 0;
int[0,N] res[Z][HORIZON];

int[0,T_LATE] assignedDelay[N];
int[0,HORIZON-1] assignedEntrySlot[N];
bool hasSchedule[N];

bool spawned[N];
bool waiting[N];
int[0,LANES-1] laneOf[N];
int[0,INTENTS-1] turnOf[N];
int[0,N] order[N];
int[0,N] waitCount = 0;

chan request[N];
chan grant[N];
chan finished[N];

int routeLength(int l, int mv) {
    int len = 0;

    for (k : int[0,MAX_ZONES-1]) {
        if (route[l][mv][k] != NO_CZ) {
            len++;
        }
    }

    return len;
}

int crossingTime(int l, int mv) {
    return routeLength(l, mv) * T_ZONE;
}

bool routeFree(int l, int mv) {
    for (k : int[0,MAX_ZONES-1]) {
        if (route[l][mv][k] != NO_CZ && occ[route[l][mv][k]] > 0) {
            return false;
        }
    }

    return true;
}

void reserve(int l, int mv) {
    for (k : int[0,MAX_ZONES-1]) {
        if (route[l][mv][k] != NO_CZ) {
            occ[route[l][mv][k]]++;
        }
    }
}

void release(int l, int mv) {
    for (k : int[0,MAX_ZONES-1]) {
        if (route[l][mv][k] != NO_CZ && occ[route[l][mv][k]] > 0) {
            occ[route[l][mv][k]]--;
        }
    }
}

bool routeConflict(int l1, int mv1, int l2, int mv2) {
    for (a : int[0,MAX_ZONES-1]) {
        for (b : int[0,MAX_ZONES-1]) {
            if (route[l1][mv1][a] != NO_CZ &&
                route[l1][mv1][a] == route[l2][mv2][b]) {
                return true;
            }
        }
    }

    return false;
}

void startWait(int id, int l, int mv) {
    waiting[id] = true;
    laneOf[id] = l;
    turnOf[id] = mv;
    waitCount++;
    order[id] = waitCount;
}

void endWait(int id) {
    if (waiting[id]) {
        for (j : int[0,N-1]) {
            if (order[j] > order[id]) {
                order[j]--;
            }
        }

        order[id] = 0;
        waiting[id] = false;

        if (waitCount > 0) {
            waitCount--;
        }
    }
}

bool mayGo(int me) {
    for (j : int[0,N-1]) {
        if (j != me && waiting[j]) {
            if (order[j] < order[me] &&
                routeConflict(laneOf[j], turnOf[j], laneOf[me], turnOf[me])) {
                return false;
            }
        }
    }

    return true;
}

bool candidateFree(int l, int mv, int d) {
    for (k : int[0,MAX_ZONES-1]) {
        if (route[l][mv][k] != NO_CZ) {
            for (q : int[0,T_ZONE-1]) {
                if (res[route[l][mv][k]][(now + d + k*T_ZONE + q) % HORIZON] > 0) {
                    return false;
                }
            }
        }
    }

    return true;
}

bool noEarlierFree(int l, int mv, int d) {
    for (e : int[T_NORMAL,T_LATE]) {
        if (e < d && candidateFree(l, mv, e)) {
            return false;
        }
    }

    return true;
}

void reserveCandidate(int l, int mv, int d) {
    for (k : int[0,MAX_ZONES-1]) {
        if (route[l][mv][k] != NO_CZ) {
            for (q : int[0,T_ZONE-1]) {
                res[route[l][mv][k]][(now + d + k*T_ZONE + q) % HORIZON]++;
            }
        }
    }
}

void releaseCandidateAt(int l, int mv, int startSlot) {
    for (k : int[0,MAX_ZONES-1]) {
        if (route[l][mv][k] != NO_CZ) {
            for (q : int[0,T_ZONE-1]) {
                if (res[route[l][mv][k]][(startSlot + k*T_ZONE + q) % HORIZON] > 0) {
                    res[route[l][mv][k]][(startSlot + k*T_ZONE + q) % HORIZON]--;
                }
            }
        }
    }
}

/*Step by step going through the Zones and not all zones at once*/
void occupyStep(int l, int mv, int step) {
    if (route[l][mv][step] != NO_CZ) {
        if (occ[route[l][mv][step]] > 0) {
            badOcc = true;
        }

        occ[route[l][mv][step]]++;
    }
}

bool stepFree(int l, int mv, int step) {
    if (route[l][mv][step] == NO_CZ) {
        return true;
    }

    return occ[route[l][mv][step]] == 0;
}

void releaseStep(int l, int mv, int step) {
    if (route[l][mv][step] != NO_CZ && occ[route[l][mv][step]] > 0) {
        occ[route[l][mv][step]]--;
    }
}

nta.system:
N0 = Vehicle(0, NORTH, STRAIGHT);
S1 = Vehicle(1, SOUTH, STRAIGHT);
E2 = Vehicle(2, EAST, TURN_RIGHT);
W3 = Vehicle(3, WEST, TURN_LEFT);

C = Controller();
T = Tick();

system N0, S1, E2, W3, C, T;
